begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('978964d1-79ee-52ce-b61c-4333fdbf7e13', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '17:30:00', null, '振替 / 検定練習', '今回の問題を解いたところ、また、読み飛ばしと不等号の向き違いが発生しました。線を引いて読むことをしているので、本番はしっかり落ち着いてください、不等号の向きは今一度くらべられるものがOOより大きいなら開いている方と認識させました。ほかに、他スプライトの既存パラメータの場所がわからなかったそうです。これは知らなきゃできないので場所を確認しました。', '読み飛ばしに注意してく大歳', null),
  ('5a4e9c61-d65d-57fb-b0b5-5fa29322619b', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '17:30:00', null, '振替 / 検定練習', '最初に前回の振り返りをしまｈした。能力的には問題はないが、文章の煩わしさから主語と目的語がずれていたり、条件の範囲の文章読解に2，3ミスやらていました。 今回解いた問題はミスがありませんでした。すごいよ！！定義が本質的にわかってなかった感じがして、文章通りそのまま作っていた感じがして、検定を終わったら定義の利用の仕方を深く学んでいけたらいいと思う。', null, null),
  ('e38e47d9-fd59-58cf-9f35-bbc02f4112c0', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '16:30:00', null, '通常 / 検定練習', '時間内で余裕で解き終わっていたし、アレンジも十字架を打つたびに向きがランダムに帰ってくるもので評価されるものができていたので問題ないです。', null, null),
  ('25a160e3-47de-5d67-8166-bf6fa584d544', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-27', '16:30:00', null, '通常 / 検定練習', '終わってみた感じにどこかしらにバグを残していて悩んでいました。答えを最初から確認していったところ、ずっとを描かれていない所に差しこまれていました。ややわからない所が余計なものを足す癖を見えました。そして、「まで待つ」の表現が解いてるときはわからなかったが、答え合わせのときにすぐに気づけました。だが、わからない所があったとしても最後まで進めているのは良かったです。なので、バグると視野が狭くなる傾向があるので、落ち着いてコード欄から似た表現を探しすようにアドバイスしました。', null, null),
  ('8c3b5dee-4a17-59aa-b47b-763531769899', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '通常 / ゲーム作成', '前半はタイピングと休憩で終わってしまいましたが、後半はすごい集中力を発揮して宇宙バトル1の内容をすべて終わらせました。敵の動きと弾丸の発射までできました。「先生、これで合ってる？」と確かめながら進めていきました。', null, '時間帯: その他
タイピング: 基本的な文字の練習をしていました
盛り上がり: 作ったゲームを、お迎えの時にきた弟さんに遊んでもらって嬉しそうでした'),
  ('89043e2b-a3f5-5608-90e8-abd6d418feca', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '通常 / 基本操作コースで基礎を固める', 'リンゴを落下させて、地面に落ちたらコスチュームを変えるというのは問題なく作れていました。 スコアのつけ方が分からなかったようですが、どういうときに1点加えるのか聞くと、プレイヤーがリンゴに触れたときだと理解しました。 後半はアレンジに入りました。プレイヤーの周りに長方形を描いて当たり判定を広くしていました。 x座標をランダムに変えるのをやっていなかったので途中で勧めましたが、気が進まなかったみたいです。', null, '時間帯: その他
盛り上がり: アレンジを楽しんでいました'),
  ('5ad53d81-b41a-5e32-8583-1bfc4dc2cf97', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-25', null, null, '通常 / 自由作品', 'とても集中して取り組めました。Scratchで遊んだゲームをアルスパークに再現してくれました。途中、「2回クリックされたら」という動作を入れようと困っていたので、変数を使うことを提案しました。本人にとって新しい考え方だったようです。最後まで完成しませんでしたが、作りたいものが伝わってきました。コスチュームの変更のタイミングなど、細かいところまで気を配れていて素晴らしかったです。', '余裕があれば続きをやりたいです。', '時間帯: その他
タイピング: 来週はやりたいです！！！！
盛り上がり: 最後に作品を紹介し合って、楽しむことができました！'),
  ('4ec02a5c-454f-575f-a228-c8738992a273', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-25', null, null, '通常 / 追跡ゲームの応用 迷路チーズ', '一度遊ぶと、なんとなくゲームの構成が分かったようでした。ネズミの動きのプログラムはとてもスムーズにいきました。座標もしっかり理解できていて素晴らしかったです。「歩数」に切り替えるのもバッチリでした。壁に当たったときのプログラムに時間がかかりましたが、「止まっているように見えるだけ」とアドバイスしたところ、自分で考えてプログラムすることができていました。チーズも、座標の下限と上限の考え方を共有して、乱数をうまく使ってできていました。 最後にゆうれいのプログラムにとりかかりましたが、時間がなくて最後までできませんでした。次回に持ち越しです。', '幽霊のプログラムつづき', '時間帯: その他
タイピング: 丁寧にタイピングできていました！！
盛り上がり: 楽しく取り組むことができました！'),
  ('688dcf34-901a-51f0-a3c7-188ba71f4768', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-25', null, null, '振替 / ジャンプの動きをマスターする', '垂直ジャンプの動きを作る時にx座標とy座標を取り違えていましたが、横に動いてしまったのを見てすぐに気づいていました。また、ジャンプするためには繰り返しブロックを使えばよいことは分かっていましたが、繰り返しの仕方が間違っていました。そこで、「上に動き続ける→下に動き続ける」という流れを説明すると、それをコードに起こすことができました。 変数には慣れているようで、スコアの変数は初期化してから更新することができていました。 テキストの内容が全て終わったので最後はアレンジを加えていました。スコアが一定以上になると卵の速度が上がるというものでした。このとき判定に「もしスコア=〇なら」を使っていてうまくいかなかったので、等号を不等号にすると一瞬ではなくずっと作動することを伝えました。', null, '時間帯: その他
タイピング: 集中していました
盛り上がり: こちらが何か助言すると納得した様子を見せていました。ゲームをアレンジしているときは特に楽しそうでした。'),
  ('0df904f8-4a90-5367-a795-6bf3e0af896a', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '18:40:00', null, '通常 / 前回の回答合わせ&２級の過去問で問題の慣れ', '問題の文章の書き方が、ややこしいのが１級の問題なので、文章がつながっている部分をどのように理解するか？がポイントなのかな？と思いました。 読み飛ばしに関してはないものの、うっかり〜まで待つ〜の部分を間違えたりするために小さなバグになってしまいそれを見つけられないという感じ。時間がかかる問題なので、１つのミスが全体に影響してしまうことを、痛感している様子でした。 その後に２級の問題を慣れのためにやってもらいましたが、２級は比較的簡単にできた様子でした。', null, 'タイピング: なし'),
  ('0fa1d16c-c746-5ba2-b9cd-7c9e68dd74ee', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / 検定３級 1回目', '問題のやり方が慣れてないためか、ブロックを全部繋げてしまったり、文章の１行目を読みとばし、ブロックの使い慣れなどができなかった様子でした。 ただし、一度説明したら、なるほどと理解していたので、来週月曜日もう一度やってみると違うかなと思っています。 基本的な条件分岐などに関しては問題なくできていたので、問題ないなと思います。', null, 'タイピング: なし'),
  ('a1b03030-125b-5841-b921-407fa2634944', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / メッセージを送る▶︎うごきが先にあった後にメッセージが送られて、違うスプライトが受け取った時にまた動作する 見本の動作 ガチャガチャhttps://app.arspark.jp/contents/8680', 'いつもチュートリアルをみて動作をするだけでは、学びにならないかなと思ったので、ガチャガチャのコスチュームがボタンを押されたら代わり、その後にメッセージを送る。送られた相手がまた動きを行うの部分だけを、一緒にやってみました その後に自分でキャラクターを作ってもらい、自由作品としてみました。 爆弾のコスチュームを変えた後に、棒人間が表示されるというプログラムを書き（ほぼ見本と同じだが・・）、自分なりには満足していた様子でした。', null, 'タイピング: だいぶタイピングにも慣れてきているので、短い単語のタイピング練習であれば今後は少しずつ増やしてあげてもいいのかもと思います。
盛り上がり: 表示、隠す、ずっとなど基本的な部分に関しては理解ができてきている様子。 メッセージなどの部分に関してはどういう関係性になっているのか？をすべてはまだ理解できていない様子なので。すこしずつリレーションのプログラミングを増やしていければいいかなと思います'),
  ('0fa16543-f73e-5007-abd9-fa65176ea690', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '17:30:00', null, '通常 / キャッチゲーム応用編', 'アイテムを落とすプログラムに少し困りました。初期位置の設定も、うまくブロックを組み合わせてプログラムできていました。高さを制御するプログラムもy座標を思い出せていたのでバッチリでした。落下の後、上に戻るプログラムに少し難儀しました。座標で制御するというアイデアがなかなか出てこないようです。 スコアのプログラムは全部自分でプログラムできていて素晴らしかったです。得点も、自分なりに考えて工夫できていました。アレンジとして、落ちたコップが割れる動き、コインのコスチュームの変化をつけてくれました。完成品にも満足そうでした。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 前向きに取り組んでくれました。'),
  ('8da58bd7-12b3-5929-bb39-507db2e3ce0e', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '16:30:00', null, '通常 / 図形を描く 〇を描く→オリンピックを描く （△を描く） 最後に作品を作ってみる', '〇は難しいと言っていましたが、360度の考え方を説明すると、最終的にはなんとなく理解できたようです。角度の考え方を自分の中で少し整理し、描くことができていました。ペンの使い方は、前回やったことを覚えていたのでバッチリでした。 オリンピックのマークも位置をきちんと調整して取り組めました。最後に自由作品として、円を使った花を描いてくれました！', null, 'タイピング: 授業前から集中して取り組んでいました。得点も高く、満足そうでした。
盛り上がり: となりのたつきくんを気にしつつ取り組んでいました。楽しそうで良かったです。'),
  ('d3f41a18-8e3d-5395-a650-c530d0facded', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '16:30:00', null, '通常 / ３級 応用問題 B019_mission', 'まで繰り返す〜というブロックを何回も使っているのにも関わらず、まで待つ〜のブロックを使っていたため、ボールの動作が動かない＆表示されないというバグに繋がっていた。 ブロックを繋げることに関しては以前よりもできるようになったものの、ちょっとしたミスが見受けられる。 当日もその部分が顕著にならなければいいのだけど、１回わからないという頭の思考になってしまうと考えることをやめてしまうので、完璧さを求めることで、ある意味問題嫌いにならなければいいなと思う', null, 'タイピング: なし'),
  ('ad29ae7f-e0d7-57cd-a335-2d38b95128a3', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-24', '16:30:00', null, '通常 / 図形を描く □ 〇 △ ペンツールの使い方（正方形を描く-ペンツール）', 'たのしく取り組めました！', null, 'タイピング: 正方形を描く（レッスン）・〇とオリンピックマークと自由作品/アルスパーク'),
  ('b7ab6d32-6ae8-549c-8967-d307edb2537a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-24', '17:30:00', null, '通常 / ４級 応用問題 E019_mission', '問題の読み飛ばしがあり、バグにも気がついてない様子。今日は集中力がとても切れていた感じがしていて、そういう意味で文章の読むことを途中で諦めてしまった感じがある、 当日ちゃんとどの部分をやったのかキチンとチェックしながらやることを伝えて、本日は終わりました。', null, 'タイピング: なし'),
  ('1982bede-a1d0-5567-8c29-fe8d82a76511', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '18:40:00', null, '通常 / ４級問題過去問 2回目', '特にヒントを求めることもなく、時間内に解き終わっていました。 アレンジでは、とても楽しそうにスプライトに手書きのイラストを付け足して喜んでいました。 「検定」というものに対しての理解はあやふやなところもありますが、問題文の通りに作成すると一つのゲームが出来上がり、それに対しるアレンジも推奨される、ということ自体を楽しんでいるように見えました。', null, '盛り上がり: 30分で一つのゲームができること、それのアレンジで少し遊んでも、注意されずに褒められることが、とても嬉しそうでした。'),
  ('58611892-3d31-57b4-a96e-c28ab73f7a2f', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, null, '2023-02-24', '18:40:00', null, '休み（未対象） / 振替をお休み', null, null, null),
  ('0d3b047b-4884-5491-84fd-492ce643c79e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-20', '17:30:00', null, '通常 / スプライトごとの変数を使う', '今回作るのが以前作ったシューティングゲームに似ていることに気づき、そのコードを見返してキャラクターの移動とビームの発射を作りました。そのあと、プレイヤーごとにHPを作ってみようと促しましたが、一撃当たると試合終了になるのがいいと言って説得できなかったため、そこで中止にしました。しゅうくんも同じものを作っていたので、最後に2人で対戦してもらいました。', null, 'タイピング: 時間切れになったときは残念そうでした
盛り上がり: 少し詰まると嫌になってしまう様子が見られました。最後にしゅうくんと対戦しているときは楽しそうでした'),
  ('9cab0c40-6054-5d08-b4c3-b137f13dba1f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-16', '16:30:00', null, '通常 / 宇宙バトルを応用してゾンビゲームを作る', '前回で宇宙バトル2の内容がだいたい作れていたようなので、きちんと理解できているか確認しました。矢印キーによる操作、「～へ行く」を使ったビームの発射、「スクリプトを止める」の使い方について、コードを参照しながら質問しました。ここはこういう意味だよねとすらすら答えられていて、内容をマスターできていることがわかりました。 そのあと、宇宙バトルを応用して新しいゲームを作ってみようと誘導し、ゾンビをたおせに入りました。宇宙バトルと同じようなスクリプトも多かったので途中まで問題なく進んでいたのですが、1つバグが起こりました。「端に触れたら隠す」というコードで一番最初から端に触れていたので、次回はそのことに気付いて修正してもらいたいです。', 'ゾンビをたおせ1の続き', 'タイピング: 楽しく取り組んでいました
盛り上がり: 最初に遊んだ段階から、ゾンビをたおせに興味を持っていました'),
  ('9f0694c2-91d3-5df5-b5c6-4bdf5441f967', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '17:30:00', null, '通常 / 新しくコードを知ろう', '先週の続いてゾンビゲームを作りました。作り終えた時に何か新しく知れたことあると聞いたところ、「ではない」とか「クローン」が答えてくれました。条件分岐の利用は慣れてきたそうです。 次に、乱数を理解するためにさいころを作りました。ランダム性を表現することに使えることを共有できたと思います。 さいごに、乱数と「では待つ」使うためにチーズを探せ」を作りました。ミミの動きに関して、上下左右に動く動きをまず右方向に座標や向きがどう変化するか確認してのち、ほか3方向も自走して作れていました。今選択してるスプライトがどの位置でどの向きをしているか曖昧な感じでしたので、確認方法も一緒に共有しました。', 'チーズを探せ続き', 'タイピング: 何回も取り組んでいました
備考: 体調に変化が起こったら言おう'),
  ('147efc44-f737-5005-84ea-6b889e95ee6d', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '16:30:00', null, '通常 / 検定問題4級応用問題2', '比較的集中して取り組めていたようです。周りの様子に流されやすいようでした。タイピングを熱心にやりすぎた影響で、振り返りの時間を十分にとることができませんでした。やっている再中も「分からない」と聞いてくれましたが、本番は文にある日本語の意味が理解できなくても質問はできないので、心配です。 間違えたポイントは何か所かありました。どれも自分が良く知っている考え方・ブロックですが、文にある日本語から意味を抽出して知っているものに置き換えるのが大変苦手なようです。合格はできそうな出来でした。', null, 'タイピング: 分からないキーがあると、キーボードをぐしゃぐしゃにしていました。もったいないです。こだまの森を最後までクリアしました。'),
  ('8373c0ce-369a-56cf-bff4-44bb26f291df', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '17:30:00', null, '通常 / 追跡ゲーム続きから（変数設定）', '変数とスコアの設定を説明しました。なんとなく分かったようです。「数字を入れる箱」として変数を紹介しました。変数が特定の値になったときに、スプライトを表示したり背景を変えたりするスクリプトも紹介しました。よく理解できている印象でした。ずっと加点されてしまう現象がおきたので、音を鳴らすブロックをうまく使うことを説明しました。 アレンジとして、ゲームクリアの表示・音を鳴らすことをしていました。最後に「すべてを止める」を使って、しっかり終えることができてので良かったです。', null, 'タイピング: 丁寧に取り組めていました！
盛り上がり: 最後、お父さんに見てもらって嬉しそうでした！'),
  ('1bbcae0c-316a-5dd8-b33e-11ca175583b5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '16:30:00', null, '通常 / こわざ（ピクセル・幽霊の効果など）を使う', 'とても楽しく取り組めていました。「ピクセル化」「幽霊化」のブロックも「～ずつ変える」「～にする」の違いも把握して使いこなせていました。数を変化させて試せていたのでとても良かったです。 40、41どちらもよくできていました。「歩かす」「色を変える」などタイミングも考慮してプログラムできていました。使い方は十分に理解できたようです。文字を打つのもだんだん安定してきました。アルファベットのドリルを見せてくれました。', null, 'タイピング: 集中して取り組めていました。タイプミスも少なかったです。'),
  ('be8488af-de7a-558f-99bd-ce4fb18fa9d8', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-21', '17:30:00', null, '通常 / 検定準備（検定問題2級応用問題5）', 'とても集中して取り組むことができていました。時間もちょうどよかったです。アレンジとして音を追加してくれました。 取り組んでいる最中に分からないことがあったようですが、演算の種類や変数名に間違いがないかなど、細かい確認するポイントを説明したところ、自分で間違いを発見することができたようです。 自信もかなりある様子でした。', null, 'タイピング: 本人がどうしてもやりたくないそうなのでスキップしました。来週は必ずやります。'),
  ('66022e38-1def-5d7d-accd-cdecf6ad5ae0', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '17:30:00', null, '通常 / 検定練習', '前回に続いて検定の問題を解きました。4級の問題はアレンジも含めてものの15分で終わってしまったので完璧にできていました。「次に上の級も試してみる？」ときいたらやると答えたので、3級の問題も解きました。こちらはアレンジも含め5分時間が余りました。凡ミス1か所で能力的には問題はありませんでした。アレンジに関しては、4級をやった時はbgmをつけるだけで簡素すぎて加点が少なくなるよと伝えたところ、3級では体力をつけてゲームオーバー演出も作れて十分よくできていました。3級も安心して合格できると思います。', null, null),
  ('285ef1e9-7acb-5fa1-ab63-4c042b610e7b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-21', '16:30:00', null, '通常 / 自由にアレンジしよう', '先週作ったパンを飛ばしてアルスタッフを倒すゲームの続きを作りました。元の作品に寄せず、サラちゃんのアイデアを中心に作っていきました。途中飛ばしたパンが手元に戻ってこないとき、やりたいこととコードを対応させながら自分自身でコードの位置を直せるように誘導させました。スタッフの判定を1回きりにさせたくて悩んでいたので、「コードを止める」ブロックを種類を含めて説明してあげました。これまでこのブロックをなんとなくつかっていた気がしたのでここで確認できたと思います。動きだけでは物足りない気がしたので、変数をつけて簡単な演算も作るように誘導しました。ノーヒントでは手が進んでいなかったので、統合のブロック持ってきて、これを使って考えてみてと誘導したら、自走して作れました。いい感じに完成したので楽しくできたとおも増す。', null, 'タイピング: 良いスコアを狙うために何回もやり直しが目立ちました
盛り上がり: こちらからはサラちゃんの考えを聞いてから少しだけ注文したのでストレスをためずに気持ちよくできていました。'),
  ('4cf90d19-2161-588f-b395-b0447599b26c', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-20', '17:30:00', null, '通常 / 特定のスプライトのみの変数を使う', '二人対戦のシューティングゲームを作りました。 弾丸のクローンを作るのですが、「クローンされたとき」のブロックを忘れていて動きませんでした。そこで、そのブロックがなかったらクローンで作られた分身が何をするのかわからないよねと伝えました。そして、以前作った一人プレイのシューティングゲームのコードを見て思い出してもらいました。また、クローンが適切なタイミングで削除されていなかったので、どういうときに消せばいいか聞くと、試行錯誤したあと削除のコードを作ることができました。 そのあと、それぞれのプレイヤーにHPを作るというのをやりました。変数を作成するときに「このスプライトのみ」にする方法を教え、2つのスプライトが別々に変数(HP)を持っている様子をイラストで伝えました。', null, 'タイピング: 記録が少し上がっていました
盛り上がり: お手本のゲームを見せたとき、面白そうと言ってくれました。'),
  ('54b7091e-3de8-5c79-acfc-d96ca9ed17ad', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-20', '16:30:00', null, '通常 / 検定練習', '2級の検定の練習問題を解きました。問題は難なく全て迷うことなく解けていていました。だが、ほかのスプライトのコスチューム番号「調べるにある水色ブロック」をコードの表し方が知らなかったそうです。このブロックはほかのコスチュームの既存のパラメータを変数として使えるので使える幅が広がること共有しました。ただ、このようなわからない所があったにもかかわらず、飛ばして解くことができたの検定の問題慣れができていると思います。', 'じゃんけんのやつの答え直し', null),
  ('be2ed75c-0120-5f5c-ab86-0ff7b0efb24c', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2023-02-20', '17:30:00', null, '休み（未対象）', null, null, null),
  ('ff77c728-2d30-5d7b-95ab-627a0aab6fae', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-20', '16:30:00', null, '通常 / 検定３級 応用18', '３級になるととても楽勝な状態で問題を解けていました。 アレンジの部分で音や数字を変えるだけではなくて他のスプライトを用意してアレンジして欲しいとリクエスト（多分それじゃないと加点されない話を伝えて）したところ、応援団を用意してそのスプライト自身に動きを作っていました。 ただ、他のスプライトを増やすとリレーションがややこしくなるから、問題と組み合わせてやるのはやだと話していたところが少し引っかかる（要は複雑になると嫌だということ）', null, 'タイピング: なし
盛り上がり: 問題自体の理解と面白くしようとする部分に関してはとてもよくできていました！'),
  ('0e10208b-1793-5c1e-9c7d-dc90f3882f0c', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-20', '16:30:00', null, '通常 / 検定４級1回目をやってみて、本番に合わせてみるか？', '最初は流れを説明し、こういう流れで進めるんだよ〜と伝えて行いました。 ほぼ一人でも解答ができている状態でかつアレンジもスプライトを追加し、跳ね返るようにしてくれていたので、基本的な動作を理解しているのだなと思います', '検定2回目を行う', 'タイピング: なし
盛り上がり: 検定をやってみてたのしかったとのこと。基本的には文章を読み解く力があるからこそ、なのかな？と思いました。'),
  ('ab2b0fd5-e7c2-592a-9fa0-6cd69418824f', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-02-18', null, null, '通常 / 続き', '前回からの続きで、基本操作コース04の追跡ゲームを作成、その後振り返りをしながらアレンジをしました。自分のアイディアを形にできて満足そうでした。乱数をマスターしようも問題なくできていました。 「ずっと」と「もし〇〇なら」の組み合わせを忘れていたのでおさらいしました。', '「乱数をマスターしよう」の振り返りと「追跡ゲームの応用」 ※追跡ゲームの応用は楽しみにしている様子でした。', '時間帯: その他
タイピング: 積極的に取り組んでいる様子。教室に来た時からタイピングを始めていた。
盛り上がり: アレンジでは敵を作るアイディアが完成した時はすごくうれしそうでした。 新しいことでも積極的に学べています。'),
  ('ecfb6ff6-62a0-5aa7-a6f5-ef760ed34b9f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / 検定２級 応用問題１１', '「りんごとばなな」の演算の使い方忘れ、バグの削除と修正がうまくいかなかったものの 、それ以外はちゃんと問題文通りに行えていました。 アレンジをすることは一回飛ばして考えて、すべての答えを正確に答えることに重きを置いた様子。答え合わせをした感じだと当日はうまくいきそうな様子なので、来週は自由作品で（本人の希望）行いたいと思います', null, '時間帯: その他
タイピング: なし'),
  ('5e52c058-b64e-5b59-9141-e7fbe6e7cfa5', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / そうすけくんが好きなものを行う、ゾンビが良かったが、結局今日は音を使うものになりました', '自分で楽器を描いて、音を選び、音程の高さなどを調節しながら音を出すというコードを行いました。〜秒待つというコードを加えた上でいくつかの楽器を押すと鳴るという仕組みをつくり楽しんでいました。', null, '時間帯: その他
タイピング: F,J,K,Lのアルファベットをタイピングする練習を行いました。割と単体のタイピングであればできそうなので少しずつ行う回数を増やしていければいいかなと思います。
盛り上がり: 今日は45分なんとか、集中力がきれずに頑張ることができました、最初にタイピングを行うことで、だいぶ机に向かう時間が増えるなという印象です'),
  ('bc382d56-d5d8-5557-ade5-3cfad8f4934d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-18', null, null, '通常 / ゲームの細分化', '最初に先週解いた検定の問題を軽く答えあわせしました。どんなゲームに作ったの問尋ねながら、問題文と見比べながら確認していきました。わかりにくかったところを聞くと、コードを止めるところがはてなを思い浮かべていました。 次に宇宙バトル2を作りました。ゲームを遊んでみて、どのスプライトがどんな動きをしているかは口で答えられていました。ただ、それをコードに作り始めると、上手く対応ができていませんでした。一部使うブロックを提示したら、ほかのブロックも持ってこられていてコードをくみ上げられていました。作りたいことのトリガーとなるコードを提示すれば作り進められる能力はできている思います。ゲームは完成はできました。', '検定', '時間帯: その他
タイピング: 着実に打てる文字が増えてきました'),
  ('4524047e-80c8-52f8-bf3f-88d29fe3673c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-18', null, null, '通常 / 基本操作コース04 追跡ゲーム＞ポイント、背景チェンジ、レベルアップの文字表示、アレンジ', '色々と質問しながら、変数の使い方、メッセージの送り方、ずっと〜がないとコードが作動しないなど、ポイントを押さえながら学習。その後に自分でアレンジ〜になった時にもうひとつコインを追加して、減点する〜やスコアを０に戻すなど自分で手を加えることを行いました。', null, '時間帯: その他
タイピング: あまりタイピングは得意ではない様子で、時間をかけてゆっくり行っていました。
盛り上がり: アレンジになった時に発想がとてもすばらしく、もう一つコインを出して、０にしてなんとかクリアにならないようにするという状態を作っていました。 変数の〜にするや〜づつ変わる、の違いもちゃんと理解でき、使い分けができていたと思います'),
  ('4c6033ca-e2fa-5124-b1aa-eac053eb9b91', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '18:40:00', null, '通常 / １級過去問３問目', '50分と時間が長いため受験のみ（前回の答え合わせはしないで、問題数を多く解く方に比重を置くことにしました。）１箇所だけどうしてもバグになってしまう箇所がある様子で、そこがうまくいけば〜と話していたので、おおかたはできている様子。 来週２問分の答え合わせをして、試験に挑みたいと思います', null, 'タイピング: タイピングは板についてきているので、次回のマイパソの結果が楽しみです。'),
  ('b60b6530-0ea1-5e59-95d9-2041a420eb3e', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '17:30:00', null, '通常 / ４級問題 エントリー第15回応用課題1', '途中で少ししゃべったり姿勢が崩れたりもしましたが、時間内に最後までできていました。 「ステージの場所」という指示を見落として、背景の指定ブロックをスプライトの方へ入れてしまっていましたが、他はできていました。問題文の読み落としに注意するよう伝えました。', null, 'タイピング: 練習モードをいくつかやっていました。
盛り上がり: 答え合わせをしながら、正解を確認しては嬉しそうにしていました。 問題を見た瞬間、「さらちゃんの天狗の動きだ！」とおもしろがっていました。'),
  ('0b6e5a69-c6f6-58c3-bc9c-4db3793ad457', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '18:40:00', null, '通常 / 検定過去問 3回目', '遅刻してきたため、3回目の応用問題受験のみ、 見た感じでは、手応えありな様子でした。 次回の月曜日に答え合わせ', null, null),
  ('66d2b964-63fe-55c1-8986-df1553bbff19', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '16:30:00', null, '通常 / ペンツールで図形を描く→【小技】アル君グルグル＿スタンプ（https://app.arspark.jp/contents/21971）', '四角を描くところから、スタンプのペンツールをつかって、花火の作品を作成するまで頑張ってみました。 彼女の良いところはきちんと説明された部分に関してはとても理解をしようという意欲があるので、今回のようにゲーム性というよりかはアート的な作品を作ることで、角度の問題などを理解してくれる感じがします。', null, 'タイピング: どちらも１級を目指して何回も練習していました、高得点をマークしていたので次回は必ず受験させてあげる方がいいかなと思います
盛り上がり: 自分でもスタンプ機能が楽しいと話していました')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
